CREATE DATABASE  IF NOT EXISTS `khanhpaintdealerdatabase` /*!40100 DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci */ /*!80016 DEFAULT ENCRYPTION='N' */;
USE `khanhpaintdealerdatabase`;

SET FOREIGN_KEY_CHECKS = 0;

DROP TABLE IF EXISTS `basetypes`;
CREATE TABLE `basetypes` (
  `base_id` int NOT NULL AUTO_INCREMENT,
  `base_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`base_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


LOCK TABLES `basetypes` WRITE;

INSERT INTO `basetypes` VALUES (1,'Base A','Là sơn gốc phân nhóm trắng/màu nhạt, sở hữu hàm lượng tinh màu trắng tinh khiết titan dioxide ($TiO_2$) cao. Cốt sơn có độ đậm đặc và độ che phủ lớn, chuyên dụng để sử dụng trực tiếp làm sơn trắng hoặc dùng làm nền để pha chế các phân khúc màu sắc siêu nhạt (Tone Pastel). Không thể pha các gam màu trung tính hoặc màu đậm từ Base A.'),(2,'Base B','Là sơn gốc phân nhóm màu trung tính nhạt, có hàm lượng tinh màu trắng tinh khiết ở mức vừa phải. Cốt sơn được thiết kế tối ưu để tiếp nhận và hiển thị chính xác các gam màu sáng vừa, màu trung tính nhẹ hoặc màu Pastel có sắc độ đậm hơn nhóm A. Ít khi được sử dụng trực tiếp làm sơn trắng vì độ che phủ gốc thấp hơn Base A.'),(3,'Base B','Là sơn gốc phân nhóm màu trung tính nhạt, có hàm lượng tinh màu trắng tinh khiết ở mức vừa phải. Cốt sơn được thiết kế tối ưu để tiếp nhận và hiển thị chính xác các gam màu sáng vừa, màu trung tính nhẹ hoặc màu Pastel có sắc độ đậm hơn nhóm A. Ít khi được sử dụng trực tiếp làm sơn trắng vì độ che phủ gốc thấp hơn Base A.');
UNLOCK TABLES;


DROP TABLE IF EXISTS `brands`;
CREATE TABLE `brands` (
  `brand_id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `origin` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`brand_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


LOCK TABLES `brands` WRITE;
INSERT INTO `brands` VALUES (1,'Jotun','Na Uy','Jotun nổi tiếng với hệ thống pha màu vi tính đa dạng và thân thiện với sức khỏe người dùng. Tại Việt Nam, hãng cung cấp các giải pháp toàn diện bao gồm: sơn trang trí, sơn hàng hải và sơn công nghiệp');
UNLOCK TABLES;

