DROP TABLE IF EXISTS `orders`;
CREATE TABLE `orders` (
  `order_id` int NOT NULL AUTO_INCREMENT,
  `customer_id` int NOT NULL,
  `sales_rep_id` int DEFAULT NULL,
  `tech_id` int DEFAULT NULL,
  `shift_id` int DEFAULT NULL,
  `total_amount` decimal(14,2) NOT NULL DEFAULT '0.00',
  `status` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `street_address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ward_id` int DEFAULT NULL,
  PRIMARY KEY (`order_id`),
  KEY `customer_id` (`customer_id`),
  KEY `sales_rep_id` (`sales_rep_id`),
  KEY `tech_id` (`tech_id`),
  KEY `shift_id` (`shift_id`),
  KEY `fk_orders_wards` (`ward_id`),
  CONSTRAINT `fk_orders_wards` FOREIGN KEY (`ward_id`) REFERENCES `wards` (`ward_id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_1` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`customer_id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_2` FOREIGN KEY (`sales_rep_id`) REFERENCES `employees` (`employee_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_3` FOREIGN KEY (`tech_id`) REFERENCES `employees` (`employee_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_4` FOREIGN KEY (`shift_id`) REFERENCES `shifts` (`shift_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


LOCK TABLES `orders` WRITE;
UNLOCK TABLES;

DROP TABLE IF EXISTS `productlines`;
CREATE TABLE `productlines` (
  `line_id` int NOT NULL AUTO_INCREMENT,
  `brand_id` int NOT NULL,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_interior` tinyint(1) NOT NULL DEFAULT '0',
  `coverage_rate` decimal(8,2) DEFAULT NULL,
  `drying_time` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `gloss_level` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `recommended_layers` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`line_id`),
  KEY `brand_id` (`brand_id`),
  CONSTRAINT `productlines_ibfk_1` FOREIGN KEY (`brand_id`) REFERENCES `brands` (`brand_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


LOCK TABLES `productlines` WRITE;
INSERT INTO `productlines` VALUES (1,1,'Jotashield Bền Màu Toàn Diện',0,NULL,NULL,NULL,NULL,'Jotashield Bền Màu Toàn Diện là sản phẩm sơn ngoại thất được yêu thích nhất Đông Nam Á*. Trải qua các bài thử nghiệm nghiêm ngặt cùng với các sản phẩm sơn ngoại thất cao cấp và được chứng nhận bởi các phòng thí nghiệm độc lập, Jotashield Bền MàuToàn Diện được bảo chứng là giải pháp bảo vệ tốt nhất cho những ngôi nhà chống chọi với điều kiện thời tiết khắc nghiệt, mang đến sự bảo vệ hoàn hảo cho ngôi nhà, đáp ứng nhu cầu khắc khe của chủ nhà.'),(2,1,'Jotashield Bền Màu Toàn Diện',0,11.10,'2',NULL,'2','Jotashield Bền Màu Toàn Diện là sản phẩm sơn ngoại thất được yêu thích nhất Đông Nam Á*. Trải qua các bài thử nghiệm nghiêm ngặt cùng với các sản phẩm sơn ngoại thất cao cấp và được chứng nhận bởi các phòng thí nghiệm độc lập, Jotashield Bền MàuToàn Diện được bảo chứng là giải pháp bảo vệ tốt nhất cho những ngôi nhà chống chọi với điều kiện thời tiết khắc nghiệt, mang đến sự bảo vệ hoàn hảo cho ngôi nhà, đáp ứng nhu cầu khắc khe của chủ nhà.');
UNLOCK TABLES;

DROP TABLE IF EXISTS `productvariants`;
CREATE TABLE `productvariants` (
  `variant_id` int NOT NULL AUTO_INCREMENT,
